import{_ as a,o as e,c as t,S as o}from"./chunks/framework.DZlzLDBr.js";const b=JSON.parse('{"title":"Burying Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Burying-Cards.md","filePath":"Burying-Cards.md","lastUpdated":null}'),i={name:"Burying-Cards.md"};function n(s,r,d,l,u,h){return e(),t("div",null,[...r[0]||(r[0]=[o('<h1 id="burying-cards" tabindex="-1">Burying Cards <a class="header-anchor" href="#burying-cards" aria-label="Permalink to &quot;Burying Cards&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="what-burying-does" tabindex="-1">What burying does <a class="header-anchor" href="#what-burying-does" aria-label="Permalink to &quot;What burying does&quot;">​</a></h2><p>Burying removes a card from today’s session and brings it back tomorrow. It does <strong>not</strong> reset or change scheduling values (interval, stability, difficulty).</p><h2 id="how-to-bury" tabindex="-1">How to bury <a class="header-anchor" href="#how-to-bury" aria-label="Permalink to &quot;How to bury&quot;">​</a></h2><p>During review:</p><ul><li>press <code>B</code>, or</li><li>open the More menu and choose <strong>Bury</strong>.</li></ul><p>If you skip the same card three times in one session, Sprout offers a <strong>Bury for today?</strong> prompt.</p><h2 id="when-cards-return" tabindex="-1">When cards return <a class="header-anchor" href="#when-cards-return" aria-label="Permalink to &quot;When cards return&quot;">​</a></h2><p>Buried cards are automatically unburied at local midnight.</p><h2 id="check-buried-cards" tabindex="-1">Check buried cards <a class="header-anchor" href="#check-buried-cards" aria-label="Permalink to &quot;Check buried cards&quot;">​</a></h2><p>Open <a href="./Card-Browser">Card Browser</a> and filter <strong>Stage = Buried</strong>.</p><h2 id="limits-and-related-behavior" tabindex="-1">Limits and related behavior <a class="header-anchor" href="#limits-and-related-behavior" aria-label="Permalink to &quot;Limits and related behavior&quot;">​</a></h2><ul><li>Burying is temporary (today only).</li><li>Burying does not delete cards.</li><li>For long-term removal from review, use <a href="./Suspending-Cards">Suspend</a>.</li></ul>',14)])])}const p=a(i,[["render",n]]);export{b as __pageData,p as default};
